/* ── AppShell responsive ─────────────────────────── */
function AppShell({ children }) {
  const { w, h } = useWindowSize();
  // Sur mobile: plein écran. Sur desktop: on simule un téléphone centré.
  const isMobile = w < 600;

  const phoneStyle = isMobile
    ? {
        width: "100%",
        height: "100%",
        minHeight: "100vh",
        background: C.bg,
        borderRadius: 0,
        overflow: "hidden",
        boxShadow: "none",
        fontFamily: "Georgia,serif",
        position: "relative",
        display: "flex",
        flexDirection: "column",
      }
    : {
        width: Math.min(420, w * 0.95),
        height: Math.min(900, h * 0.96),
        background: C.bg,
        borderRadius: 40,
        overflow: "hidden",
        boxShadow: "0 32px 80px rgba(0,0,0,0.5),0 0 0 10px #1A1A1A,0 0 0 12px #333",
        fontFamily: "Georgia,serif",
        position: "relative",
        display: "flex",
        flexDirection: "column",
      };

  const wrapStyle = isMobile
    ? { width: "100%", minHeight: "100vh", background: C.bg }
    : {
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        minHeight: "100vh",
        background: `linear-gradient(135deg,${C.primaryDark} 0%,#0A1A50 100%)`,
        padding: 16,
      };

  return (
    <div style={wrapStyle}>
      <div style={phoneStyle}>
        {children}
      </div>
    </div>
  );
}

